import pickle
import json
import time
import os
import hashlib
from pathlib import Path
from typing import Any, Optional, Dict
from datetime import datetime, timedelta


class APIResponseCache:
    def __init__(self, cache_dir: str = ".api_cache", default_ttl: int = 3600, use_pickle: bool = True):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(exist_ok=True)
        self.default_ttl = default_ttl
        self.use_pickle = use_pickle
        self.extension = ".pkl" if use_pickle else ".json"
        
    def _get_cache_key(self, key: str) -> str:
        return hashlib.md5(key.encode()).hexdigest()
    
    def _get_cache_path(self, cache_key: str) -> Path:
        return self.cache_dir / f"{cache_key}{self.extension}"
    
    def _get_metadata_path(self, cache_key: str) -> Path:
        return self.cache_dir / f"{cache_key}.meta"
    
    def set(self, key: str, data: Any, ttl: Optional[int] = None) -> None:
        cache_key = self._get_cache_key(key)
        cache_path = self._get_cache_path(cache_key)
        meta_path = self._get_metadata_path(cache_key)
        
        ttl = ttl if ttl is not None else self.default_ttl
        expiration_time = time.time() + ttl
        
        if self.use_pickle:
            with open(cache_path, 'wb') as f:
                pickle.dump(data, f, protocol=pickle.HIGHEST_PROTOCOL)
        else:
            with open(cache_path, 'w') as f:
                json.dump(data, f)
        
        metadata = {
            'expiration': expiration_time,
            'created': time.time(),
            'original_key': key
        }
        
        with open(meta_path, 'w') as f:
            json.dump(metadata, f)
    
    def get(self, key: str) -> Optional[Any]:
        cache_key = self._get_cache_key(key)
        cache_path = self._get_cache_path(cache_key)
        meta_path = self._get_metadata_path(cache_key)
        
        if not cache_path.exists() or not meta_path.exists():
            return None
        
        with open(meta_path, 'r') as f:
            metadata = json.load(f)
        
        if time.time() > metadata['expiration']:
            self.delete(key)
            return None
        
        if self.use_pickle:
            with open(cache_path, 'rb') as f:
                return pickle.load(f)
        else:
            with open(cache_path, 'r') as f:
                return json.load(f)
    
    def delete(self, key: str) -> bool:
        cache_key = self._get_cache_key(key)
        cache_path = self._get_cache_path(cache_key)
        meta_path = self._get_metadata_path(cache_key)
        
        deleted = False
        if cache_path.exists():
            cache_path.unlink()
            deleted = True
        if meta_path.exists():
            meta_path.unlink()
            deleted = True
        
        return deleted
    
    def exists(self, key: str) -> bool:
        return self.get(key) is not None
    
    def clear_expired(self) -> int:
        count = 0
        current_time = time.time()
        
        for meta_file in self.cache_dir.glob("*.meta"):
            try:
                with open(meta_file, 'r') as f:
                    metadata = json.load(f)
                
                if current_time > metadata['expiration']:
                    cache_key = meta_file.stem
                    cache_path = self.cache_dir / f"{cache_key}{self.extension}"
                    
                    if cache_path.exists():
                        cache_path.unlink()
                    meta_file.unlink()
                    count += 1
            except Exception:
                continue
        
        return count
    
    def clear_all(self) -> int:
        count = 0
        for file in self.cache_dir.glob("*"):
            if file.is_file():
                file.unlink()
                count += 1
        return count
    
    def get_stats(self) -> Dict[str, Any]:
        total_entries = len(list(self.cache_dir.glob("*.meta")))
        expired_entries = 0
        total_size = 0
        current_time = time.time()
        
        for meta_file in self.cache_dir.glob("*.meta"):
            try:
                with open(meta_file, 'r') as f:
                    metadata = json.load(f)
                
                if current_time > metadata['expiration']:
                    expired_entries += 1
                
                cache_key = meta_file.stem
                cache_path = self.cache_dir / f"{cache_key}{self.extension}"
                if cache_path.exists():
                    total_size += cache_path.stat().st_size
                total_size += meta_file.stat().st_size
            except Exception:
                continue
        
        return {
            'total_entries': total_entries,
            'expired_entries': expired_entries,
            'valid_entries': total_entries - expired_entries,
            'total_size_bytes': total_size,
            'cache_dir': str(self.cache_dir)
        }
    
    def get_or_set(self, key: str, fetch_func, ttl: Optional[int] = None) -> Any:
        cached_data = self.get(key)
        if cached_data is not None:
            return cached_data
        
        data = fetch_func()
        self.set(key, data, ttl)
        return data


class TimedCache:
    def __init__(self, cache_dir: str = ".timed_cache", use_pickle: bool = True):
        self.cache = APIResponseCache(cache_dir=cache_dir, use_pickle=use_pickle)
    
    def cache_response(self, endpoint: str, params: Optional[Dict] = None, ttl: int = 3600):
        def decorator(func):
            def wrapper(*args, **kwargs):
                cache_key = f"{endpoint}:{str(params)}:{str(args)}:{str(kwargs)}"
                
                cached = self.cache.get(cache_key)
                if cached is not None:
                    return cached
                
                result = func(*args, **kwargs)
                self.cache.set(cache_key, result, ttl)
                return result
            
            return wrapper
        return decorator


